func (c *aliLSWriter) Init(config string) error {
	err := json.Unmarshal([]byte(config), c)
	if err != nil {
		return err
	}

	if c.FlushWhen > CacheSize {
		c.FlushWhen = CacheSize
	}

	prj := &LogProject{
		Name:			c.Project,
		Endpoint:		c.Endpoint,
		AccessKeyID:		c.KeyID,
		AccessKeySecret:	c.KeySecret,
	}

	store, err := prj.GetLogStore(c.LogStore)
	if err != nil {
		return err
	}

	c.store = store

	c.group = append(c.group, &LogGroup{
		Topic:	proto.String(""),
		Source:	proto.String(c.Source),
		Logs:	make([]*Log, 0, c.FlushWhen),
	})

	c.groupMap = make(map[string]*LogGroup)
	for _, topic := range c.Topics {

		lg := &LogGroup{
			Topic:	proto.String(topic),
			Source:	proto.String(c.Source),
			Logs:	make([]*Log, 0, c.FlushWhen),
		}

		c.group = append(c.group, lg)
		c.groupMap[topic] = lg
	}

	if len(c.group) == 1 {
		c.withMap = false
	} else {
		c.withMap = true
	}

	c.lock = &sync.Mutex{}

	if len(c.Formatter) > 0 {
		fmtr, ok := logs.GetFormatter(c.Formatter)
		if !ok {
			return fmt.Errorf("the formatter with name: %s not found", c.Formatter)
		}
		c.formatter = fmtr
	}

	return nil
}
